int main() {
    int n = 6;
    int steps = 0;
    while (n != 1) {
        int odd = n & 1;
        if (odd != 0) {
            n = n + n + n + 1;
        } else {
            int half = 0;
            int test = 0;
            while (test + test < n) {
                half += 1;
                test = half;
            }
            n = half;
        }
        steps += 1;
    }
    return steps;
}
